import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import axios from 'axios';

const Login = () => {
    const [isLogin, setIsLogin] = useState(true);
    const [formData, setFormData] = useState({
        email: '',
        password: '',
        confirmPassword: '',
        name: ''
    });
    const [rememberMe, setRememberMe] = useState(false);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');
    const [showForgotPassword, setShowForgotPassword] = useState(false);
    const [forgotPasswordEmail, setForgotPasswordEmail] = useState('');
    const [forgotPasswordLoading, setForgotPasswordLoading] = useState(false);
    const navigate = useNavigate();

    // API configuration
    const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

    // Check if already logged in
    React.useEffect(() => {
        const token = localStorage.getItem('accessToken');
        if (token) {
            navigate('/dashboard');
        }
    }, [navigate]);

    // Handle input changes
    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({
            ...prev,
            [name]: value
        }));
    };

    // Validate form
    const validateForm = () => {
        setError('');

        // Email validation
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        if (!formData.email || !emailRegex.test(formData.email)) {
            setError('Please enter a valid email address');
            return false;
        }

        // Password validation
        if (!formData.password || formData.password.length < 6) {
            setError('Password must be at least 6 characters long');
            return false;
        }

        // Signup validations
        if (!isLogin) {
            if (!formData.name || formData.name.length < 2) {
                setError('Name must be at least 2 characters long');
                return false;
            }
            if (formData.password !== formData.confirmPassword) {
                setError('Passwords do not match');
                return false;
            }
        }

        return true;
    };

    // Handle login
    const handleLogin = async (e) => {
        e.preventDefault();
        setError('');
        setSuccess('');

        if (!validateForm()) return;

        setLoading(true);
        try {
            const response = await axios.post(`${API_BASE_URL}/auth/login`, {
                email: formData.email,
                password: formData.password
            });

            const { token, user } = response.data;

            // Store token
            localStorage.setItem('token', token);
            localStorage.setItem('user', JSON.stringify(user));

            // Set axios default header
            axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;

            // Navigate to dashboard
            navigate('/dashboard');

        } catch (err) {
            const errorMessage = err.response?.data?.message || 
                               err.response?.data?.error || 
                               'Login failed. Please check your credentials.';
            setError(errorMessage);
        } finally {
            setLoading(false);
        }
    };

    // Handle signup
    const handleSignup = async (e) => {
        e.preventDefault();
        setError('');
        setSuccess('');

        if (!validateForm()) return;

        setLoading(true);
        try {
            const response = await axios.post(`${API_BASE_URL}/auth/register`, {
                name: formData.name,
                email: formData.email,
                password: formData.password
            });

            const { token, user } = response.data;

            // Store token
            localStorage.setItem('token', token);
            localStorage.setItem('user', JSON.stringify(user));

            // Set axios default header
            axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;

            setSuccess('Account created successfully! Redirecting...');

            setTimeout(() => {
                navigate('/dashboard');
            }, 2000);

        } catch (err) {
            const errorMessage = err.response?.data?.message || 
                               err.response?.data?.error || 
                               'Registration failed. Please try again.';
            setError(errorMessage);
        } finally {
            setLoading(false);
        }
    };

    // Handle forgot password
    const handleForgotPassword = async (e) => {
        e.preventDefault();
        setError('');
        setSuccess('');

        if (!forgotPasswordEmail) {
            setError('Please enter your email address');
            return;
        }

        setForgotPasswordLoading(true);
        try {
            await axios.post(`${API_BASE_URL}/auth/forgot-password`, {
                email: forgotPasswordEmail
            });

            setSuccess('Password reset link has been sent to your email.');
            setForgotPasswordEmail('');

        } catch (err) {
            const errorMessage = err.response?.data?.message || 
                               'Failed to send reset link. Please try again.';
            setError(errorMessage);
        } finally {
            setForgotPasswordLoading(false);
        }
    };

    // Handle Google login
    const handleGoogleLogin = () => {
        // You would integrate actual Google OAuth here
        alert('Google OAuth integration would go here');
        // Example: window.location.href = `${API_BASE_URL}/auth/google`;
    };

    // Handle form submission
    const handleSubmit = (e) => {
        e.preventDefault();
        if (isLogin) {
            handleLogin(e);
        } else {
            handleSignup(e);
        }
    };

    // Styles
    const styles = {
        container: {
            display: 'flex',
            minHeight: '100vh',
            fontFamily: 'Arial, sans-serif',
            backgroundColor: '#f5f5f5'
        },
        leftPanel: {
            flex: 1,
            background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
            color: 'white',
            display: 'flex',
            flexDirection: 'column',
            justifyContent: 'center',
            padding: '40px',
            position: 'relative',
            overflow: 'hidden'
        },
        rightPanel: {
            flex: 1,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            padding: '40px',
            backgroundColor: 'white'
        },
        card: {
            width: '100%',
            maxWidth: '400px',
            backgroundColor: 'white',
            borderRadius: '10px',
            boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)',
            padding: '40px'
        },
        title: {
            fontSize: '24px',
            fontWeight: 'bold',
            marginBottom: '10px',
            color: '#333'
        },
        subtitle: {
            fontSize: '14px',
            color: '#666',
            marginBottom: '30px'
        },
        input: {
            width: '100%',
            padding: '12px',
            marginBottom: '15px',
            border: '1px solid #ddd',
            borderRadius: '5px',
            fontSize: '16px'
        },
        button: {
            width: '100%',
            padding: '12px',
            backgroundColor: '#667eea',
            color: 'white',
            border: 'none',
            borderRadius: '5px',
            fontSize: '16px',
            fontWeight: 'bold',
            cursor: 'pointer',
            marginTop: '10px'
        },
        buttonDisabled: {
            width: '100%',
            padding: '12px',
            backgroundColor: '#ccc',
            color: '#666',
            border: 'none',
            borderRadius: '5px',
            fontSize: '16px',
            fontWeight: 'bold',
            cursor: 'not-allowed',
            marginTop: '10px'
        },
        googleButton: {
            width: '100%',
            padding: '12px',
            backgroundColor: 'white',
            color: '#333',
            border: '1px solid #ddd',
            borderRadius: '5px',
            fontSize: '16px',
            cursor: 'pointer',
            marginTop: '10px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center'
        },
        error: {
            backgroundColor: '#fee',
            color: '#c33',
            padding: '10px',
            borderRadius: '5px',
            marginBottom: '15px',
            fontSize: '14px'
        },
        success: {
            backgroundColor: '#dfd',
            color: '#383',
            padding: '10px',
            borderRadius: '5px',
            marginBottom: '15px',
            fontSize: '14px'
        },
        link: {
            color: '#667eea',
            textDecoration: 'none',
            cursor: 'pointer',
            fontSize: '14px'
        },
        divider: {
            display: 'flex',
            alignItems: 'center',
            margin: '20px 0'
        },
        dividerLine: {
            flex: 1,
            height: '1px',
            backgroundColor: '#ddd'
        },
        dividerText: {
            padding: '0 10px',
            color: '#666',
            fontSize: '12px'
        },
        checkbox: {
            marginRight: '8px'
        },
        checkboxLabel: {
            fontSize: '14px',
            color: '#666'
        }
    };

    // Forgot Password Screen
    if (showForgotPassword) {
        return (
            <div style={styles.container}>
                <div style={styles.leftPanel}>
                    <div>
                        <h1 style={{ fontSize: '48px', marginBottom: '10px' }}>TMS</h1>
                        <h2 style={{ fontSize: '24px', marginBottom: '20px' }}>Ticket Management System</h2>
                        <p>Reset your password securely</p>
                    </div>
                </div>

                <div style={styles.rightPanel}>
                    <div style={styles.card}>
                        <h2 style={styles.title}>Reset Password</h2>
                        <p style={styles.subtitle}>Enter your email to receive reset instructions</p>

                        {error && <div style={styles.error}>{error}</div>}
                        {success && <div style={styles.success}>{success}</div>}

                        <form onSubmit={handleForgotPassword}>
                            <input
                                type="email"
                                placeholder="Email"
                                value={forgotPasswordEmail}
                                onChange={(e) => setForgotPasswordEmail(e.target.value)}
                                style={styles.input}
                                required
                            />

                            <button
                                type="submit"
                                disabled={forgotPasswordLoading}
                                style={forgotPasswordLoading ? styles.buttonDisabled : styles.button}
                            >
                                {forgotPasswordLoading ? 'Sending...' : 'Send Reset Link'}
                            </button>
                        </form>

                        <div style={{ marginTop: '20px', textAlign: 'center' }}>
                            <span 
                                style={styles.link}
                                onClick={() => setShowForgotPassword(false)}
                            >
                                ← Back to Login
                            </span>
                        </div>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div style={styles.container}>
            {/* Left Panel */}
            <div style={styles.leftPanel}>
                <div>
                    <h1 style={{ fontSize: '48px', marginBottom: '10px' }}>TMS</h1>
                    <h2 style={{ fontSize: '24px', marginBottom: '20px' }}>Ticket Management System</h2>
                    <p>Streamline your workflow with our powerful ticket management solution</p>
                </div>
            </div>

            {/* Right Panel - Login/Signup Form */}
            <div style={styles.rightPanel}>
                <div style={styles.card}>
                    <h2 style={styles.title}>
                        {isLogin ? 'Welcome Back' : 'Create Account'}
                    </h2>
                    <p style={styles.subtitle}>
                        {isLogin ? 'Sign in to your account' : 'Create a new account'}
                    </p>

                    {/* Error/Success Messages */}
                    {error && <div style={styles.error}>{error}</div>}
                    {success && <div style={styles.success}>{success}</div>}

                    {/* Form */}
                    <form onSubmit={handleSubmit}>
                        {/* Name field for signup */}
                        {!isLogin && (
                            <input
                                type="text"
                                name="name"
                                placeholder="Full Name"
                                value={formData.name}
                                onChange={handleInputChange}
                                style={styles.input}
                                required={!isLogin}
                            />
                        )}

                        {/* Email field */}
                        <input
                            type="email"
                            name="email"
                            placeholder="Email Address"
                            value={formData.email}
                            onChange={handleInputChange}
                            style={styles.input}
                            required
                        />

                        {/* Password field */}
                        <input
                            type="password"
                            name="password"
                            placeholder="Password"
                            value={formData.password}
                            onChange={handleInputChange}
                            style={styles.input}
                            required
                        />

                        {/* Confirm Password for signup */}
                        {!isLogin && (
                            <input
                                type="password"
                                name="confirmPassword"
                                placeholder="Confirm Password"
                                value={formData.confirmPassword}
                                onChange={handleInputChange}
                                style={styles.input}
                                required={!isLogin}
                            />
                        )}

                        {/* Remember Me & Forgot Password (for login) */}
                        {isLogin && (
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '15px' }}>
                                <label style={styles.checkboxLabel}>
                                    <input
                                        type="checkbox"
                                        checked={rememberMe}
                                        onChange={(e) => setRememberMe(e.target.checked)}
                                        style={styles.checkbox}
                                    />
                                    Remember me
                                </label>
                                <span
                                    style={styles.link}
                                    onClick={() => setShowForgotPassword(true)}
                                >
                                    Forgot password?
                                </span>
                            </div>
                        )}

                        {/* Submit Button */}
                        <button
                            type="submit"
                            disabled={loading}
                            style={loading ? styles.buttonDisabled : styles.button}
                        >
                            {loading ? 'Processing...' : (isLogin ? 'Sign In' : 'Sign Up')}
                        </button>

                        {/* Divider */}
                        <div style={styles.divider}>
                            <div style={styles.dividerLine}></div>
                            <span style={styles.dividerText}>OR</span>
                            <div style={styles.dividerLine}></div>
                        </div>

                        {/* Google Button */}
                        <button
                            type="button"
                            style={styles.googleButton}
                            onClick={handleGoogleLogin}
                            disabled={loading}
                        >
                            Continue with Google
                        </button>

                        {/* Switch between Login/Signup */}
                        <div style={{ marginTop: '20px', textAlign: 'center' }}>
                            <span style={{ color: '#666', fontSize: '14px' }}>
                                {isLogin ? "Don't have an account?" : "Already have an account?"}
                            </span>
                            <span
                                style={{ ...styles.link, marginLeft: '5px' }}
                                onClick={() => {
                                    setIsLogin(!isLogin);
                                    setError('');
                                    setSuccess('');
                                }}
                            >
                                {isLogin ? 'Sign Up' : 'Sign In'}
                            </span>
                        </div>

                        {/* Terms and Privacy */}
                        <div style={{ marginTop: '20px', textAlign: 'center' }}>
                            <p style={{ fontSize: '12px', color: '#999' }}>
                                By continuing, you agree to our Terms and Privacy Policy
                            </p>
                        </div>
                    </form>
                </div>
            </div>
        </div>
    );
};

export default Login;
